vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

vec2 uv2;
vUv -= 0.5;
vUv *= uAspect.xy;

noise = texture(sampler_pw_noise_lq,uv3);
noise *= (noise >= .9);

float dist = 1;
float inten = 1;
float mask = 0;
ret1 = 0;
int anz = 2;
float n = 0;
cont = 0;
while (n <= anz) {
uv2 = vUv;
    dist = 1-fract(1.0/anz*n+q6); //evtl sqrt !

    inten =  (dist)*(1-dist)*6;
    vec2 uv3 =  fract(1*uv2*dist+.55);

    neu = 1*GetPixel(uv3) + GetBlur1(uv3)*0;
    ret1 = max(ret1,neu*inten);
vec3 ret2 = mix(0,tex2d(sampler_rand03,uv3),ret1.x);
ret2 = mix(ret2,tex2d(sampler_rand04,uv3),ret1.y);
ret2 = mix(ret2,tex2d(sampler_rand05,uv3),ret1.z);
ret1 = ret2;
    cont = max(cont,(-GetPixel(uv3)+GetBlur1(uv3+q7))*inten);
n++;
}

rs2 = .1*cos(vUv*3+vec2(uTime/12,5)) + .1*ret1;
vec3 dots = clamp01(.005/length(rs2)) * vec3 (q9,q10,q11);

ret = -.1*ret1 + 1*dots*(.1+10*ret1) + (cont)*(1+slow_roam_cos)/5;
ret += .0*ret1;
//ret = GetPixel(vUvOriginal+.5);

  fragColor = ret;
}
